import{_ as o,o as i,c as t,ae as a}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"AGENTS And Provider Expansion Design","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-03-26-agents-and-provider-expansion-design.md","filePath":"superpowers/specs/2026-03-26-agents-and-provider-expansion-design.md"}'),r={name:"superpowers/specs/2026-03-26-agents-and-provider-expansion-design.md"};function n(d,e,s,l,c,p){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="agents-and-provider-expansion-design" tabindex="-1">AGENTS And Provider Expansion Design <a class="header-anchor" href="#agents-and-provider-expansion-design" aria-label="Permalink to &quot;AGENTS And Provider Expansion Design&quot;">​</a></h1><p><strong>Date:</strong> 2026-03-26</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>This design covers three related changes for Notemd:</p><ol><li>Add a project-level <code>AGENTS.md</code> as the execution authority for Codex/agent workflows without rewriting <code>GEMINI.md</code>.</li><li>Add front-end validation guidance for the <code>Doubao</code> preset so users get explicit feedback when the model field still looks like an unset Ark endpoint placeholder.</li><li>Extend the centralized LLM provider registry with <code>Baidu Qianfan</code> and <code>SiliconFlow</code>, including runtime support, API connection testing, documentation, and regression tests.</li></ol><p>These changes are grouped because they all improve agent/operator reliability: one at repository workflow level, one at provider UX level, and one at provider surface level.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>The provider architecture should continue to use <code>src/llmProviders.ts</code> as the single source of truth for provider metadata. New providers must be represented by registry definitions and flow through transport-driven dispatch in <code>src/llmUtils.ts</code> instead of adding more provider-name branching.</p><p>Provider validation should be implemented as a small pure helper that returns warnings for UI consumers. The settings tab can render those warnings and gate connection tests when the provider configuration is obviously incomplete. This keeps the validation logic testable and reusable without embedding brittle UI-only conditionals.</p><p>The new <code>AGENTS.md</code> should be repository-local and opinionated about Notemd&#39;s build, verification, documentation, release, and asset-upload workflow. It should explicitly document that GitHub releases for this plugin must include <code>README.md</code> in addition to <code>main.js</code>, <code>manifest.json</code>, and <code>styles.css</code>.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><h3 id="_1-repository-guidance" tabindex="-1">1. Repository Guidance <a class="header-anchor" href="#_1-repository-guidance" aria-label="Permalink to &quot;1. Repository Guidance&quot;">​</a></h3><ul><li>Create <code>AGENTS.md</code> at repository root.</li><li>Keep <code>GEMINI.md</code> unchanged.</li><li>Include project overview, key files, build/test commands, release workflow, documentation sync rules, provider-extension rules, and Git safety rules.</li></ul><h3 id="_2-provider-validation" tabindex="-1">2. Provider Validation <a class="header-anchor" href="#_2-provider-validation" aria-label="Permalink to &quot;2. Provider Validation&quot;">​</a></h3><ul><li>Add a small validation helper near the provider registry.</li><li>Detect when <code>Doubao</code> still uses the placeholder endpoint model, or when the configured model does not resemble an Ark endpoint ID.</li><li>Surface warnings in the settings UI before users run tasks or connection tests.</li></ul><h3 id="_3-provider-expansion" tabindex="-1">3. Provider Expansion <a class="header-anchor" href="#_3-provider-expansion" aria-label="Permalink to &quot;3. Provider Expansion&quot;">​</a></h3><ul><li>Add <code>Baidu Qianfan</code> and <code>SiliconFlow</code> presets to the registry.</li><li>Keep them on the existing <code>openai-compatible</code> transport.</li><li>Assign API-test metadata so the connection test validates the actual configured model.</li><li>Update docs in both <code>README.md</code> and <code>README_zh.md</code>.</li></ul><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><p>The connection-test path should keep current behavior for runtime/API errors. The new provider-validation layer should only handle obviously incomplete local configuration and produce user-facing warnings. It should not attempt to guess or auto-rewrite provider models.</p><p>For <code>Doubao</code>, the UX should nudge users toward a valid Ark endpoint configuration while leaving room for provider-side model naming changes. A warning is safer than destructive normalization.</p><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h2><ul><li>Add unit tests for provider validation warnings.</li><li>Extend provider registry tests to assert presence of <code>Baidu Qianfan</code> and <code>SiliconFlow</code>.</li><li>Extend provider runtime/API tests to assert both providers use the openai-compatible runtime and chat-first API probing.</li><li>Re-run full build and Jest suite after implementation.</li></ul><h2 id="review-notes" tabindex="-1">Review Notes <a class="header-anchor" href="#review-notes" aria-label="Permalink to &quot;Review Notes&quot;">​</a></h2><p>A dedicated spec-review subagent was not used here because this session does not have explicit user authorization to delegate sub-agent work. This design was self-reviewed against the repository&#39;s current provider architecture and release workflow.</p>',24)])])}const g=o(r,[["render",n]]);export{u as __pageData,g as default};
